// Parse TOML frontmatter from Hugo markdown file
const input = $input.first().json;
const content = input.body.fileContent;
const fileName = input.body.fileName;
const slug = input.body.slug;
const siteBaseUrl = input.body.siteBaseUrl;

// Extract TOML frontmatter between +++ delimiters
const frontmatterMatch = content.match(/^\+\+\+([\s\S]*?)\+\+\+/);

let title = '';
let date = '';
let draft = false;
let tags = [];
let categories = [];
let bodyContent = '';

if (frontmatterMatch) {
  const fm = frontmatterMatch[1];

  // Parse title
  const titleMatch = fm.match(/title\s*=\s*['"](.+?)['"]/);
  if (titleMatch) title = titleMatch[1];

  // Parse date
  const dateMatch = fm.match(/date\s*=\s*['"](.+?)['"]/);
  if (dateMatch) date = dateMatch[1];

  // Parse draft
  const draftMatch = fm.match(/draft\s*=\s*(true|false)/);
  if (draftMatch) draft = draftMatch[1] === 'true';

  // Parse tags
  const tagsMatch = fm.match(/tags\s*=\s*\[([^\]]+)\]/);
  if (tagsMatch) {
    tags = tagsMatch[1].match(/['"]([^'"]+)['"]/g)
      ?.map(t => t.replace(/['"]*/g, '')) || [];
  }

  // Parse categories
  const catMatch = fm.match(/categories\s*=\s*\[([^\]]+)\]/);
  if (catMatch) {
    categories = catMatch[1].match(/['"]([^'"]+)['"]/g)
      ?.map(c => c.replace(/['"]*/g, '')) || [];
  }

  // Extract body (everything after frontmatter)
  bodyContent = content.replace(/^\+\+\+[\s\S]*?\+\+\+/, '').trim();
}

// Take first 500 words as excerpt for AI context
const excerpt = bodyContent.split(/\s+/).slice(0, 500).join(' ');

const postUrl = `${siteBaseUrl}/posts/${slug}/`;

return [{
  json: {
    title,
    date,
    draft,
    tags,
    categories,
    slug,
    fileName,
    postUrl,
    excerpt
  }
}];

// Build the HuggingFace request body safely with proper JSON escaping
const data = $input.first().json;

const tagsStr = data.tags.join(', ');
const excerptClean = data.excerpt.substring(0, 800).replace(/[\n\r]+/g, ' ').replace(/["]/g, "'");

const userPrompt = `Write a compelling LinkedIn post (150-200 words) announcing my new blog article.

Title: ${data.title}
Tags: ${tagsStr}
Article excerpt: ${excerptClean}
URL: ${data.postUrl}

Requirements:
- Professional but engaging tone
- Include 2-3 relevant hashtags derived from the tags
- End with a call to action to read the full article
- Include the article URL
- Use line breaks for readability
- Maximum 2-3 emojis
- Do NOT include the word 'hashtag', just use the # symbol`;

const requestBody = {
  model: 'Meta-Llama-3.1-8B-Instruct',
  messages: [
    {
      role: 'system',
      content: 'You are a professional LinkedIn content writer. Write engaging posts that drive clicks and engagement. Keep the tone professional yet approachable.'
    },
    {
      role: 'user',
      content: userPrompt
    }
  ],
  max_tokens: 400,
  temperature: 0.7
};

return [{
  json: {
    ...data,
    hfRequestBody: requestBody
  }
}];

// Extract the AI-generated LinkedIn post text from HF response
const hfResponse = $input.first().json;
const prevData = $('Prepare HF Request').first().json;

let linkedinText = '';

if (hfResponse.choices && hfResponse.choices.length > 0) {
  linkedinText = hfResponse.choices[0].message.content.trim();
} else if (hfResponse[0] && hfResponse[0].generated_text) {
  linkedinText = hfResponse[0].generated_text.trim();
} else {
  // Fallback: generate a simple post
  const hashtags = prevData.tags.slice(0, 3).map(t => '#' + t.replace(/\s+/g, '')).join(' ');
  linkedinText = `New blog post: "${prevData.title}"\n\nCheck it out here: ${prevData.postUrl}\n\n${hashtags}`;
}

return [{
  json: {
    ...prevData,
    linkedinText
  }
}];

// Build LinkedIn post request body with person ID from profile lookup
const profile = $input.first().json;
const postData = $('Format LinkedIn Post').first().json;

const personId = profile.sub;

const linkedinBody = {
  author: `urn:li:person:${personId}`,
  lifecycleState: 'PUBLISHED',
  specificContent: {
    'com.linkedin.ugc.ShareContent': {
      shareCommentary: {
        text: postData.linkedinText
      },
      shareMediaCategory: 'ARTICLE',
      media: [
        {
          status: 'READY',
          originalUrl: postData.postUrl,
          title: {
            text: postData.title
          }
        }
      ]
    }
  },
  visibility: {
    'com.linkedin.ugc.MemberNetworkVisibility': 'PUBLIC'
  }
};

return [{
  json: {
    linkedinBody
  }
}];
